VALUES
  ('public-health-specialist-moex-00277', 'public-health-specialist', 'public-health-specialist-moex-113-50d43abc', 'sub-public-health-specialist-03', NULL, 'single_choice', '在日常生活中，難免直接或間接接觸食品添加劑、農藥、殺蟲劑等潛在有毒物質，環境中的 化學物質想要妥適運用，首先須找出不致中毒的劑量，通常會利用動物實驗的結果來計算風 險，下列何者為風險評估中常用以評估非線性劑量效應之閾值標準？', '["最大殘留容許量（Maximalresiduelevel,MRL）", "每日最大安全攝取量（Acceptabledailyintake,ADI）", "危害指數（Hazardindex,HI）", "未觀察到不良效應之劑量（No-observed-adverseeffectlevel,NOAEL）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "16918ff39647", "answer_pdf_sha1": "76106db6fc46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "環境與職業衛生", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00278', 'public-health-specialist', 'public-health-specialist-moex-113-50d43abc', 'sub-public-health-specialist-03', NULL, 'single_choice', '由食物所引起的食物中毒，依照發病機制而分成不同類型，其中由於病原菌在食品中繁殖的 過程產生外毒素，攝食此食品後，外毒素作用於腸道，或經吸收進入血液循環，到達神經系 統作用於神經細胞引起中毒，屬於下列何類型之食物中毒？', '["中間型", "感染型", "仿生型", "毒素型"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "16918ff39647", "answer_pdf_sha1": "76106db6fc46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "環境與職業衛生", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00279', 'public-health-specialist', 'public-health-specialist-moex-113-50d43abc', 'sub-public-health-specialist-03', NULL, 'single_choice', '當高溫環境產生的熱壓力逾生理熱調節速率或涵容力時，熱疾病即可能發生，可即時提供水 分與電解質，採取休息與降溫等應變措施，讓身體熱壓力調適能力恢復後即可迅速復原，下 列何者不屬於這類型熱疾病？', '["熱衰竭（Heatexhaustion）", "熱暈厥（Heatsyncope）", "熱痙攣（Heatcramps）", "熱中暑（Heatstroke）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "16918ff39647", "answer_pdf_sha1": "76106db6fc46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "環境與職業衛生", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00280', 'public-health-specialist', 'public-health-specialist-moex-113-50d43abc', 'sub-public-health-specialist-03', NULL, 'single_choice', '依職業安全衛生法之相關規定，對於化學品應依其健康危害、散布情形及使用量等進行分級 管理，下列何者是化學品分級管理工具（CCB）的步驟之一？', '["劃分危害群組", "進行市場調查", "決定產品價格", "審查銷售數量"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "16918ff39647", "answer_pdf_sha1": "76106db6fc46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "環境與職業衛生", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00281', 'public-health-specialist', 'public-health-specialist-moex-113-50d43abc', 'sub-public-health-specialist-03', NULL, 'single_choice', '人因工程危害評估中最常使用量表進行工作狀態之量測，常見為問卷調查法，主要是掌握可 能之危害特徵並評估其嚴重性，下列何者屬於其危害評估之方法？', '["健康識能評估表（MandarinHealthLiteracyScale,MHLS）", "世界衛生組織生活品質問卷（WHOQOL）", "肌肉骨骼傷害問卷（NordicMusculoskeletalQuestionnaire,NMQ）", "匹茲堡睡眠品質量表（PittsburghSleepQualityIndex,PSQI）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "16918ff39647", "answer_pdf_sha1": "76106db6fc46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "環境與職業衛生", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00282', 'public-health-specialist', 'public-health-specialist-moex-113-50d43abc', 'sub-public-health-specialist-03', NULL, 'single_choice', '職業病之治療除針對症狀進行治療或緩解不適外，主要目的在於根除病因，故職業暴露之病 因診斷成為極大挑戰，尤其在暴露證據及罹病時序性特徵之蒐集是最常用於界定病因的參考 依據，基於以上原則，下列何者為最具決定性之關鍵資訊？', '["工作暴露歷史", "臨床症狀檢查", "作業環境測定", "危害特徵描述"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "16918ff39647", "answer_pdf_sha1": "76106db6fc46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "環境與職業衛生", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00283', 'public-health-specialist', 'public-health-specialist-moex-113-50d43abc', 'sub-public-health-specialist-03', NULL, 'single_choice', '當探討個別勞工的粒狀或氣狀污染物暴露評估時，將採樣器放置於勞工呼吸區域，搭配符合 法規標準的採樣設備，不需要外加及依賴動力或電力供應要求，進行長時間的連續偵測採樣， 據以評估勞工之呼吸暴露，稱之為何種採樣？', '["主動式採樣（Activesampling）", "被動式採樣（Passivesampling）", "微型感測採樣（Microsensorsampling）", "生物偵測（Biologicalmonitoring）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "16918ff39647", "answer_pdf_sha1": "76106db6fc46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "環境與職業衛生", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00284', 'public-health-specialist', 'public-health-specialist-moex-113-50d43abc', 'sub-public-health-specialist-03', NULL, 'single_choice', '下列何者不是我國職業安全衛生法針對工作場所化學品管理規範的重要項目內容？', '["危害物質安全資料表", "危害特性資料庫", "危害化學品清單", "危害標示與通識規則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "16918ff39647", "answer_pdf_sha1": "76106db6fc46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "環境與職業衛生", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00285', 'public-health-specialist', 'public-health-specialist-moex-113-50d43abc', 'sub-public-health-specialist-03', NULL, 'single_choice', '職場作業環境噪音監測時，下列何者非於執行時重要之查核事項？', '["確認是否由物理性因子作業環境監測人員執行監測，並會同職業安全衛生人員及工會或勞 工代表實施", "定義各種噪音暴露人員、過程區域之危害性評估", "是否涵蓋了工作日時量平均音壓級、連續性噪音最大值及衝擊性噪音峰值之監測", "監測結果是否能建立相似暴露族群暴露輪廓"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "16918ff39647", "answer_pdf_sha1": "76106db6fc46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "環境與職業衛生", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00286', 'public-health-specialist', 'public-health-specialist-moex-113-50d43abc', 'sub-public-health-specialist-03', NULL, 'single_choice', '臺灣針對室內空氣品質已有相關管制措施並設有管制標準，針對室內場域、管制污染物種類 及標準均有相關規定，下列敘述何者錯誤？', '["考量公眾聚集量、進出量、室內空氣污染物危害風險程度及場所之特殊需求，逐批公告場 所，像是教室、圖書室、實驗室、表演廳、禮堂、展覽室、會議廳（室）等", "定期實施室內空氣品質檢驗測定，並應定期公布檢驗測定結果；連續監測室內空氣品質， 其自動監測最新結果，應即時公布於該場所內或入口明顯處及作成紀錄", "公告場所所有人、管理人或使用人應置室內空氣品質維護管理專責人員，依室內空氣品質 維護管理計畫，執行管理維護", "室內空氣污染物包括二氧化碳、一氧化碳、甲醛、總揮發性有機化合物、細菌、真菌、粒徑 小於等於二．五微米之懸浮微粒（PM2.5）、臭氧及菸品尼古丁及其他經中央主管機關指定公 告之物質"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "16918ff39647", "answer_pdf_sha1": "76106db6fc46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "環境與職業衛生", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL)
